var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"......무작정 검을 휘둘러서 허공에 힘을 낭비할 필요는 없어.","JPN":"……むやみに剣を振り回すと力の無駄遣いになる。","ENG":"There's no need to waste my energy swinging my sword into thin air.","TWN":"……沒必要胡亂揮舞長劍浪費力量。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"칼날이 정확히 적에게 닿았을 때, 단숨에 클리포트 인자를 집속해서 폭발시킨다.","JPN":"刃が正確に敵に触れた瞬間、クリフォト・ファクターを一気に集束して爆発させる。","ENG":"When the blade makes contact with the target, I focus my Qliphoth Factor and explode it.","TWN":"在劍刃正確碰觸到敵人時，一口氣讓逆卡巴拉因子聚能爆炸。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"인과를 넘어, 불사나 부활 같은 하찮은 힘이 간섭할 여지가 없도록......","JPN":"因果を超えて、不死や復活のようなくだらない力が干渉する余地がないように……","ENG":"I'll go beyond causality and burn you up in an instant with my full power...","TWN":"使之超脫因果，擺脫不死和復活這樣的低階力量干擾……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"단숨에 최대화력으로 태워 버린다!","JPN":"一気に最高火力で燃やす！","ENG":"so that no immortality or resurrection can save you!","TWN":"一口氣將火力最大化，焚燒敵人！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"사라져라! 재활용품!!","JPN":"消えろ！　ゴミ！！","ENG":"Be gone! You recycled piece of junk!","TWN":"消失吧！可回收物！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"캬아██아아███아아......!!!!","JPN":"グア██ァァ███ァ……！！","ENG":"Ky██aa███ah!","TWN":"咳啊██啊啊███啊啊……！！！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MONSTER_NEPHILIM_START"},{"id":"L12_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"아아███아아......","JPN":"アア███ァ……","ENG":"Aa███ah...","TWN":"啊啊███啊啊……"},"stage":{"bg":"WHITE","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"아아......","JPN":"ァァ……","ENG":"Aah...","TWN":"啊啊……"},"stage":{"bg":"WHITE","bgm":"THEMA_WOLFSBANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......미나 양?","JPN":"……ミナさん？","ENG":"Mina?","TWN":"……米娜小姐？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어......? 선배?","JPN":"うん……？　先輩？","ENG":"Huh? Shiyoon?","TWN":"咦……？前輩？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"언제 온 거야. 깜짝 놀랐네.","JPN":"いつ来たの。ビックリした。","ENG":"When did you get here? You startled me.","TWN":"你什麼時候來的，嚇我一跳。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"지금 막 도착한 길입니다.","JPN":"ちょうど今着いたところですよ。","ENG":"I just got here.","TWN":"我剛到。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"강적과 싸우고 있다고 해서 서둘렀는데...... 이제 보니 그럴 필요가 없었던 것 같군요.","JPN":"強敵と戦っていると聞いて急いで来たのですが……その必要はなかったようですね。","ENG":"I rushed over when I heard you're fighting a powerful foe... But now I see that wasn't necessary.","TWN":"聽說你在跟強敵戰鬥，所以急忙趕過來……看來完全沒有必要。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데 방금 본 전투 방식...... 스승님의 검술과 비슷한데요?","JPN":"ところで先ほどの戦闘方法……師匠の剣術と似ていましたね？","ENG":"By the way, your fighting skills just now... They remind me of the Master's style.","TWN":"剛才看到的戰鬥方式……和老師的劍術很像？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"언제 배우신 거죠?","JPN":"いつ教わったんですか？","ENG":"When did you learn them?","TWN":"你什麼時候學的？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그게, 소대장이 아니라...... 다른 사람에게 배운 것 같아.","JPN":"それが、小隊長じゃなくて……他の人から教えてもらったみたい。","ENG":"Well... I didn't learn them from her, but from someone else, I think.","TWN":"那個，不是小隊長……是其他人教給我的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다른 사람이라고요? 대체 누가?","JPN":"他の人？　いったい誰から？","ENG":"Someone else? Who could it be?","TWN":"其他人？到底是誰？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"나도...... 잘 모르겠어. 분명 무척 익숙한 목소리였는데......","JPN":"私も……よくわからない。でも、すごく聞き慣れた声だったけどね……","ENG":"I'm not sure. It was a really familiar voice...","TWN":"我也……不太清楚。明明是很熟悉的聲音……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"언니......?","JPN":"姉さん……？","ENG":"Sis?","TWN":"姐姐……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"......여기까지군요.","JPN":"……ここまでですね。","ENG":"Looks like that's my cue to exit.","TWN":"……看來只能到此為止了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"제 일은 모두 끝났습니다. 이젠 헤어질 시간이군요.","JPN":"私の仕事は終わりました。もうお別れの時間です。","ENG":"My task here is finished. Time to say goodbye.","TWN":"我的事情已經全部完成，我該離開了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 도망칠 셈이냐?!","JPN":"なんだと？　逃げるつもりか？","ENG":"What? You're running away?","TWN":"什麼？你打算逃走嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"오해는 마세요. 전 당신이 두렵지 않습니다.","JPN":"誤解しないでください。あなたなんて脅威にもなりません。","ENG":"Please do not be mistaken. I'm not afraid of you.","TWN":"別誤會，我並不是懼怕你。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"무대가 아직 준비되지 않았을 뿐이죠.","JPN":"まだ舞台が用意されていないだけです。","ENG":"The stage is simply not ready for me yet.","TWN":"只是舞臺還未準備好而已。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"지금 당신과, 당신의 하찮은 제자들을 죽여 봤자 우리에겐 아무 이득이 없으니까요.","JPN":"今のあなたと、あなたの弱い弟子たちを殺しても我々には何の利益にもなりませんから。","ENG":"Killing you and your petty apprentices now won't do us any good.","TWN":"現在殺掉你和你的那些渺小弟子，對我們來說毫無益處。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"그러니 제 자비에 감사하면서 당분간은 부디 자중하시길.","JPN":"ですので、私の慈悲に感謝して当分はくれぐれも自重なさいますよう。","ENG":"So I hope you'll appreciate my mercy and keep a low profile for the time being...","TWN":"所以，感謝我的慈悲吧，然後請你自重。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"길을 잃은 발키리여.","JPN":"道に迷ったヴァルキリーよ。","ENG":"Lost Valkyrie.","TWN":"迷失的女武神。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승......","JPN":"師匠……","ENG":"Master...","TWN":"師父……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님, 들리십니까?","JPN":"師匠、聞こえますか？","ENG":"Master, can you hear me?","TWN":"師父，你能聽到嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연......?","JPN":"キズナ……？","ENG":"Sooyeon?","TWN":"李秀妍……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......다행입니다. 드디어 통신이 연결됐군요.","JPN":"……よかったです。やっと通信が復旧しました。","ENG":"Thank goodness. The signal finally got through.","TWN":"……真是萬幸，通信終於恢復了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"긴급 파견했던 시윤 군이 조금 전 연락해 왔습니다.","JPN":"緊急派遣したアキヤマ君から先ほど連絡が来ました。","ENG":"I just heard back from Shiyoon on his emergency radio.","TWN":"緊急派遣的周時雲剛剛與我聯絡了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 리치급 침식체, 네르비에가 미나 양에게 완전히 소멸되었다더군요.","JPN":"あのリッチ級の侵食体、ネルヴィエがミナさんによって完全消滅したようです。","ENG":"Mina completely destroyed the Lich-class C.O., Nervier.","TWN":"那個巫妖級的侵蝕體，尼爾比耶被米娜完全消滅了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은 아직 클리포트 인자를 제대로 다루지 못해요.","JPN":"ミナさんはまだクリフォト・ファクターをちゃんとコントロールできません。","ENG":"Mina doesn't know how to wield her Qliphoth Factor properly yet.","TWN":"米娜還無法掌控逆卡巴拉因子。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 굳이 전투복 사용료라는 웃기지도 않은 핑계까지 대서 울브즈베인을 쓰는 걸 억제해 왔죠.","JPN":"だからあえて戦闘服使用料というくだらない理由をつけて、ウルブズベインの使用を控えてもらっていました。","ENG":"That's why I came up with the ridiculous excuse of fining her for using the suit to discourage the use of Wolvesbane.","TWN":"所以我只能硬著頭皮用戰鬥服使用費的藉口，限制她持續使用狼之災禍。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 리치급 침식체를 소멸시켰다는 건......","JPN":"しかしリッチ級侵食体を消滅させたということは……","ENG":"But if she's destroyed a Lich-class C.O...","TWN":"但如果說她消滅了巫妖級的侵蝕體……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"숙명이...... 움직이기 시작했군.","JPN":"宿命が……動き始めたのか。","ENG":"Her destiny... has begun to shift.","TWN":"說明宿命……已經開始了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"알겠다. 자세한 건 회사로 돌아가서 이야기하지.","JPN":"了解。詳しい話は会社に戻ってからにしよう。","ENG":"Acknowledged. We can talk details once I return to the office.","TWN":"知道了，那詳細的就回公司再說吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 기다리고 있겠습니다.","JPN":"はい、お待ちしております。","ENG":"Yes. I'll be waiting for you.","TWN":"好的，我在公司等你。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"후훗. 저런 벌레 같은 반푼이 사령술사에게 모욕을 당할 지경이라니.","JPN":"あんな虫けら同然な出来損ないの降霊術師に侮辱されるとは。","ENG":"Heh heh. I can't believe you had to endure such an insult from that worm of a necromancer.","TWN":"哼哼，竟然被不如螻蟻的半吊子死靈術師給侮辱了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_WHOOSH_FIRE_SMALL"},{"id":"L18_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"지켜 보던 내가 다 화가 나던데.","JPN":"見ている方がイライラしたぞ。","ENG":"It actually boiled my blood to watch.","TWN":"連我都看不下去，整個火冒三丈了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"어때, 내가 대신 가서 사지를 찢어 줄까?","JPN":"どうじゃ、妾が代わりにすべて八つ裂きにしてやろうか？","ENG":"How about I go tear her from limb to limb for you?","TWN":"怎麼樣，要不要我替你去教訓他？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......아스모데우스.","JPN":"……アスモデウス。","ENG":"Asmodeus.","TWN":"……阿斯蒙蒂斯"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"아니면 뭐, 자기학대 하는 취미라도 생겼나?","JPN":"それとも、自虐趣味でもできたのか？","ENG":"Unless, of course, you've developed a penchant for masochism.","TWN":"或者說會不會其實你有自虐的愛好？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"하긴 예전부터 네가 하는 꼴을 보면 그럴 법도 하지만.","JPN":"まあ、今までの其方の様子を見ればそうもなるんじゃろうが。","ENG":"I suppose that would hardly be a surprise given how you've always abused yourself.","TWN":"從你一直以來的所作所為來看，也充分有可能。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"인간들의 속담 중에 손바닥으로 하늘을 가릴 수는 없다는 말이 있지.","JPN":"まさに釜底抽薪じゃな。","ENG":"You humans say that stick head in the sand.","TWN":"再怎樣也不可能隻手遮天。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"운명에 재갈을 물리고 숙명에 멍에를 씌워도 세상은 멈추지 않아.","JPN":"運命にくつわをはめても、宿命にくびきをつけても、世界は止まらない。","ENG":"No matter how much you bind fate and fetter destiny, you cannot stop the world from going on.","TWN":"就算命運出現波折，宿命被戴上枷鎖，世界也不會因此而停止。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"결국 너만 뒤처지게 될 뿐이다.","JPN":"結局其方だけが取り残されるのみ。","ENG":"In the end, you'll just fall behind.","TWN":"最後落單的只有你自己而已。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"그 당연한 사실을 대체 언제쯤 깨달을 생각이지?","JPN":"その当たり前の事実をいつになったら気付くのじゃ？","ENG":"When will you come to terms with this obvious truth?","TWN":"這麼簡單的事情，你到底什麼時候才能領悟呢？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"그 촉수 년도, 인형 쪼가리도, 구세주병에 걸린 등신도 나를 막을 순 없어.","JPN":"あの触手女も、被虐嗜好の傀儡も、救世主病にかかった戯け者も、妾を止めることはできぬ。","ENG":"Nobody can stop me. Not that tentacled wench, the rag doll, or the idiot with the Messiah complex.","TWN":"不管是那個觸手，還是人偶碎片，或是得了救世主病的瘋子都無法阻擋我。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"나는 네가 만들어 낸 최강의 마왕이자 북의 폭군.","JPN":"妾は其方が作り出した最強の魔王であり、北の暴君。","ENG":"I am the greatest Demon Lord of your creation, and the Tyrant of the North.","TWN":"我是你創造出的最強魔王，北方的暴君。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"잿더미를 부르는 자, 아스모데우스다.","JPN":"灰をもたらす者、アスモデウスじゃ。","ENG":"I am Asmodeus, the Ashbringer.","TWN":"是賦予世界灰燼的阿斯蒙蒂斯。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"그리고 내 발을 멈출 수 있는 자는 너뿐이지.","JPN":"そして妾を止められるのは其方しかおらぬ。","ENG":"You alone can stop my steps.","TWN":"能停滯我腳步的人只有你。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"시간은 계속 흐르고 있어. 내가 언제까지 자비를 베풀 거라고 생각하지 마라.","JPN":"時間は止まらず進み続けている。妾がいつまでも慈悲を施すと思うな。","ENG":"Time keeps flowing. Do not think I will always be so merciful.","TWN":"時間將繼續流逝，我的慈悲並不會長久下去。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"네 소중한 것들을 지키고 싶다면...... 결단을 서두르는 게 좋을 거야.","JPN":"其方の大切なものを守りたいなら……決断を急ぐがよい。","ENG":"If you wish to protect those you hold dear, you may want to make a decision soon.","TWN":"如果你想守護你珍視的一切……最好儘快做出決斷。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나도...... 알고 있어......","JPN":"私も……わかっている……","ENG":"Yes... I know...","TWN":"我……我也知道……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};